private boolean isSafeReplacement(Node node, Node replacement) {
  // First, check if the replacement node is null
  if (replacement == null) {
    return false;
  }

  // Check if the node is a getProp
  if (node.isGetProp()) {
    // Check if the replacement is also a getProp
    if (replacement.isGetProp()) {
      // If the replacement is a getProp, check if it's the same property as the node
      return replacement.getString().equals(node.getString());
    }
  } else {
    // If the node is not a getProp, check if it's a name
    if (node.isName()) {
      // If the node is a name, check if the replacement is also a name
      if (replacement.isName()) {
        // If both the node and replacement are names, check if the strings match
        return replacement.getString().equals(node.getString());
      }
    }
  }

  // If the replacement is not a name or getProp, or if the property names don't match, return false
  return false;
}
